import{_ as t,o,c as s,ah as d}from"./chunks/framework.ojwJKwrc.js";const u=JSON.parse('{"title":"Heliodor マクロベンチマーク","description":"","frontmatter":{},"headers":[],"relativePath":"ja/benchmarks/heliodor.md","filePath":"ja/benchmarks/heliodor.md"}'),a={name:"ja/benchmarks/heliodor.md"};function c(i,e,l,r,n,p){return o(),s("div",null,[...e[0]||(e[0]=[d(`<h1 id="heliodor-マクロベンチマーク" tabindex="-1">Heliodor マクロベンチマーク <a class="header-anchor" href="#heliodor-マクロベンチマーク" aria-label="Permalink to &quot;Heliodor マクロベンチマーク&quot;">​</a></h1><p>Heliodor は Veryl で書かれた大規模な RISC-V プロセッサで、Linux boot の ignored test を持っています。プロジェクト読み込み、<code>$readmemh</code> による大きなメモリ初期化、native testbench scheduling、長時間の順序回路シミュレーションをまとめて踏むので、Celox を Veryl native simulator として見るためのマクロベンチに向いています。</p><p>このベンチは通常 CI には含めません。Heliodor を <code>target/heliodor/source</code> に checkout し、<code>veryl</code> が無い場合は <code>target/heliodor/tools</code> に自動インストールし、Celox runner を測定前に build します。デフォルトでは Veryl baseline を先に測ってから Celox を走らせ、TSV サマリとフルログを <code>target/heliodor/results</code> に出します。</p><h2 id="実行" tabindex="-1">実行 <a class="header-anchor" href="#実行" aria-label="Permalink to &quot;実行&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/run-heliodor-bench.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prepare</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/run-heliodor-bench.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span></code></pre></div><p><code>run</code> は構成を変更できる診断用コマンドです。測定値を追記しますが、Celox が性能要件を満たすかは判定しません。その判定には固定構成の <code>gate</code> を使います。</p><p>デフォルトでは <code>test_soc_linux_boot</code> を Veryl Cranelift、Veryl cc、Celox の順に走らせます。Celox はその test で成功した最速 Veryl baseline の <code>HELIODOR_CELOX_TIMEOUT_MULTIPLIER</code> 倍で timeout します。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">HELIODOR_TESTS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;test_soc_linux_boot test_soc_smp_linux_boot_2hart&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">HELIODOR_RUNNERS=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;celox veryl-cranelift veryl-cc&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">scripts/run-heliodor-bench.sh </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">run</span></span></code></pre></div><p><code>HELIODOR_REF</code> を指定しない限り、Heliodor は commit <code>7ad830fc0f8506c934b61a853ce2eadfa5926b82</code> に固定します。</p><h2 id="acceptance-gate" tabindex="-1">Acceptance gate <a class="header-anchor" href="#acceptance-gate" aria-label="Permalink to &quot;Acceptance gate&quot;">​</a></h2><p>clean かつ commit 済みの Celox checkout から、再現可能な end-to-end 比較を 実行します。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/run-heliodor-bench.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gate</span></span></code></pre></div><p>gate の構成は変更できません。以下をすべて固定します。</p><ul><li>公式 repository の Heliodor commit <code>7ad830fc0f8506c934b61a853ce2eadfa5926b82</code> と clean な checkout</li><li>benchmark 所有ディレクトリにある Veryl <code>0.20.2</code>。<code>PATH</code> や <code>VERYL_BIN</code> は使わず、固定 path と <code>--version</code> の完全一致で選択</li><li>clean で途中に変化しない Celox <code>HEAD</code>。invocation ごとの空の Cargo target directory に <code>--locked</code> release build し、その成果物を実行</li><li><code>test_soc_linux_boot</code>、runner 順序 <code>veryl-cc</code>、<code>celox</code>、各 300 秒 timeout</li><li>Celox native backend、<code>O2</code>、2-state、full execution、SIR pass override なし</li><li>runner ごとに別の detached Heliodor worktree。project-local な生成物を runner 間で共有しない</li></ul><p>gate は <code>target/heliodor/results</code> の下に、新しい独立した <code>gate_&lt;timestamp&gt;.&lt;suffix&gt;</code> directory を作ります。その invocation が生成した 2 行だけを受理します。Veryl は正常終了し、対象 test の成功をちょうど 1 件、 集計を <code>1 passed, 0 failed</code> と報告する必要があります。Celox は正常終了し、 native/O2/<code>four_state=false</code>/<code>compile_only=false</code> の config 行と full-pass result 行をそれぞれちょうど 1 件報告する必要があります。実行前後で source manifest、checkout identity、runner executable hash も検査します。</p><p>subprocess 時間は monotonic nanosecond clock で測定します。両方の semantic check が成功し、Celox の process 時間が Veryl 以下の場合にだけ gate は 0 で 終了します。compile-only、partial window、runner 内部の報告時間、または正確な marker を伴わない process exit 0 は失敗です。<code>--kill-after</code> を持つ GNU <code>timeout</code> と Python 3 が必要です。</p><p>Celox は現時点で、この gate における競争力のある full Linux-boot 成功結果を 一度も出していません。コマンドの実装によって acceptance 判定を実行可能にした のであって、それ自体が性能要件の合格実績になるわけではありません。</p><h2 id="テスト" tabindex="-1">テスト <a class="header-anchor" href="#テスト" aria-label="Permalink to &quot;テスト&quot;">​</a></h2><p>Heliodor の <code>#[test]</code> module 一覧は以下で見られます。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/run-heliodor-bench.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><p>主な長時間テスト:</p><table tabindex="0"><thead><tr><th>Test</th><th>意味</th></tr></thead><tbody><tr><td><code>test_soc_linux_boot</code></td><td>Linux 5.15 single-hart boot</td></tr><tr><td><code>test_soc_smp_linux_boot_2hart</code></td><td>Linux 5.15 SMP 2-hart boot</td></tr><tr><td><code>test_soc_smp_linux_boot_4hart</code></td><td>Linux 5.15 SMP 4-hart boot</td></tr><tr><td><code>test_soc_linux_boot_71</code></td><td>Linux 7.1 single-hart boot</td></tr><tr><td><code>test_soc_smp_linux_boot_71_2hart</code></td><td>Linux 7.1 SMP 2-hart boot</td></tr><tr><td><code>test_soc_linux_boot_71v</code></td><td>Linux 7.1 vector-enabled boot</td></tr></tbody></table><h2 id="ランナー" tabindex="-1">ランナー <a class="header-anchor" href="#ランナー" aria-label="Permalink to &quot;ランナー&quot;">​</a></h2><p><code>HELIODOR_RUNNERS</code> には以下を指定できます。</p><table tabindex="0"><thead><tr><th>Runner</th><th>Command</th></tr></thead><tbody><tr><td><code>celox</code></td><td><code>target/release/examples/run_veryl_project_test --project ... --test ...</code></td></tr><tr><td><code>veryl-cc</code></td><td><code>veryl test --ignored --test ... --backend cc</code></td></tr><tr><td><code>veryl-cranelift</code></td><td><code>veryl test --ignored --test ... --backend cranelift</code></td></tr><tr><td><code>veryl-interpret</code></td><td><code>veryl test --ignored --test ... --backend interpret</code></td></tr></tbody></table><p>Celox runner は Celox の default backend を使います。x86-64 host では native x86-64 backend です。最適化プリセットは <code>CELOX_OPT_LEVEL=O0|O1|O2</code> で変えられます。</p><p>全 runner/test の timeout を固定したい場合は <code>HELIODOR_TIMEOUT_SEC</code> を指定します。Veryl baseline がまだない場合、Linux boot は single-hart 300 秒、2-hart SMP 600 秒、4-hart SMP 1800 秒などの固定 fallback を使います。</p><p><code>veryl</code> が <code>PATH</code> に無い場合、スクリプトは <code>cargo install veryl --version 0.20.2 --locked</code> を <code>target/heliodor/tools/veryl-0.20.2</code> に実行します。<code>VERYL_BIN</code>、<code>HELIODOR_VERYL_VERSION</code> で上書きできます。自動インストールを止める場合は <code>HELIODOR_INSTALL_TOOLS=0</code> を指定します。</p><h2 id="結果の意味" tabindex="-1">結果の意味 <a class="header-anchor" href="#結果の意味" aria-label="Permalink to &quot;結果の意味&quot;">​</a></h2><p><code>target/heliodor/results/results.tsv</code> は subprocess の終了 status と、 シミュレーションした test の意味上の結果を区別します。列は以下です。</p><table tabindex="0"><thead><tr><th>列</th><th>意味</th></tr></thead><tbody><tr><td><code>runner</code></td><td>runner 名</td></tr><tr><td><code>test</code></td><td>指定した Heliodor test</td></tr><tr><td><code>status</code></td><td>既存 reader のため第 3 列に残す <code>exit_status</code> の旧名</td></tr><tr><td><code>elapsed_ns</code></td><td>full pass の wall time。full pass 以外は必ず <code>NA</code></td></tr><tr><td><code>log</code></td><td>runner の完全な log</td></tr><tr><td><code>semantic_status</code></td><td><code>pass</code>、<code>fail</code>、<code>compile-only</code>、<code>unreported</code>、<code>invalid</code></td></tr><tr><td><code>exit_status</code></td><td>subprocess の終了 status</td></tr><tr><td><code>process_elapsed_ns</code></td><td>fail や compile-only を含む subprocess の monotonic elapsed time</td></tr><tr><td><code>reported_elapsed_ns</code></td><td>Celox runner 内部の elapsed。取得できない場合は <code>NA</code></td></tr></tbody></table><p>従来の <code>runner</code>、<code>test</code>、<code>status</code>、<code>elapsed_ns</code>、<code>log</code> は同じ順序で 残ります。速度結果として扱えるのは <code>semantic_status=pass</code>、 <code>exit_status=0</code> かつ <code>elapsed_ns</code> が数値の行だけです。 <code>process_elapsed_ns</code> と <code>reported_elapsed_ns</code> は診断値であり、 <code>compile-only</code>、<code>fail</code>、<code>unreported</code>、<code>invalid</code> の full-test 性能として 扱ってはいけません。</p><p>Celox については、ログ中に次の完全な行がちょうど 1 個必要です。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CELOX_TEST_RESULT test=&lt;requested-test&gt; status=pass|fail|compile-only elapsed_ns=&lt;integer&gt;</span></span></code></pre></div><p>形式不正、重複、欠落、test 名の不一致、compile-only mode との不一致、 process 終了 status との不一致は pass になりません。 <code>HELIODOR_CELOX_COMPILE_ONLY=1</code> が正常終了しても、<code>semantic_status</code> は <code>compile-only</code>、<code>elapsed_ns</code> は <code>NA</code> です。</p><p>既存の 5 列 TSV は次回実行時に atomic に移行します。最初の内容を <code>results.tsv.v1.bak</code> に保存し、参照先の Celox log から意味上の結果を 復元できない行は <code>unreported</code> または <code>invalid</code> にします。process の 終了 status が 0 という事実だけで Celox full pass に昇格させることは ありません。</p><p>parser/migration と acceptance gate の fixture は、Heliodor や compiler を checkout・実行せずにテストできます。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/tests/run-heliodor-bench-results.sh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/tests/run-heliodor-bench-gate.sh</span></span></code></pre></div><h2 id="現状の注意" tabindex="-1">現状の注意 <a class="header-anchor" href="#現状の注意" aria-label="Permalink to &quot;現状の注意&quot;">​</a></h2><p>このマクロベンチで Celox 側が記録するのは、現時点では意味上の結果、process の結果、wall-clock time です。Heliodor は <code>$display</code> で simulated cycle count を出しますが、Celox の detailed test runner は display event を捨てているため、cycle 抽出は Celox runner が display forwarding を持つまで Veryl runner のログ側だけで利用できます。</p>`,40)])])}const b=t(a,[["render",c]]);export{u as __pageData,b as default};
